package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonElement;
import com.google.gson.JsonIOException;
import com.google.gson.JsonSyntaxException;
import com.google.gson.stream.JsonWriter;
import com.google.gson.internal.Streams;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;
import org.mockito.Mockito;

import java.io.IOException;

class GsonToJsonTest {

  private Gson gson;
  private JsonWriter writer;
  private JsonElement jsonElement;

  @BeforeEach
  void setUp() {
    gson = new Gson();
    writer = mock(JsonWriter.class);
    jsonElement = mock(JsonElement.class);
  }

  @Test
  void toJson_shouldSetAndResetWriterPropertiesAndCallStreamsWrite() throws IOException {
    // Arrange
    when(writer.isLenient()).thenReturn(false);
    when(writer.isHtmlSafe()).thenReturn(false);
    when(writer.getSerializeNulls()).thenReturn(false);

    // Act
    gson.toJson(jsonElement, writer);

    // Assert
    InOrder inOrder = inOrder(writer);
    // Verify properties set to true or expected values
    inOrder.verify(writer).isLenient();
    inOrder.verify(writer).setLenient(true);
    inOrder.verify(writer).isHtmlSafe();
    inOrder.verify(writer).setHtmlSafe(true);
    inOrder.verify(writer).getSerializeNulls();
    inOrder.verify(writer).setSerializeNulls(false);

    // Verify Streams.write called with jsonElement and writer
    // Streams.write is a static method, so we cannot verify directly with Mockito.
    // We rely on no exception thrown and writer methods called correctly.

    // Verify properties reset to original values in finally block
    inOrder.verify(writer).setLenient(false);
    inOrder.verify(writer).setHtmlSafe(false);
    inOrder.verify(writer).setSerializeNulls(false);
  }

  @Test
  void toJson_shouldWrapIOExceptionInJsonIOException() throws IOException {
    // Arrange
    when(writer.isLenient()).thenReturn(true);
    when(writer.isHtmlSafe()).thenReturn(true);
    when(writer.getSerializeNulls()).thenReturn(true);
    doThrow(new IOException("io error")).when(writer).setLenient(true);
    // We simulate IOException during Streams.write by mocking Streams.write via spy on Gson class
    // But Streams.write is static and final, so cannot mock easily without PowerMockito.
    // Instead, simulate IOException by creating a custom JsonElement that throws on write.

    JsonElement throwingJsonElement = new JsonElement() {
      @Override
      public boolean equals(Object obj) {
        return super.equals(obj);
      }
    };

    // We'll simulate IOException by mocking Streams.write via reflection to throw IOException.
    // Since Streams.write is static and final, not mockable here.
    // So instead, test IOException thrown by Streams.write indirectly by creating a JsonWriter that throws IOException on some method called by Streams.write.
    // This is complicated; simpler to test IOException thrown by Streams.write is wrapped.

    // Alternative: create a JsonWriter subclass that throws IOException on any write.
    JsonWriter throwingWriter = new JsonWriter(new java.io.StringWriter()) {
      @Override
      public void setLenient(boolean lenient) {
        // do nothing
      }
      @Override
      public void setHtmlSafe(boolean htmlSafe) {
        // do nothing
      }
      @Override
      public void setSerializeNulls(boolean serializeNulls) {
        // do nothing
      }
      @Override
      public boolean isLenient() {
        return true;
      }
      @Override
      public boolean isHtmlSafe() {
        return true;
      }
      @Override
      public boolean getSerializeNulls() {
        return true;
      }
      // override flush or close or write method to throw IOException
      @Override
      public void flush() throws IOException {
        throw new IOException("flush error");
      }
    };

    // Act & Assert
    JsonIOException thrown = assertThrows(JsonIOException.class, () -> {
      gson.toJson(jsonElement, throwingWriter);
    });
    assertTrue(thrown.getCause() instanceof IOException);
    assertEquals("flush error", thrown.getCause().getMessage());
  }

  @Test
  void toJson_shouldWrapAssertionErrorWithVersionInfo() throws IOException {
    // Arrange
    when(writer.isLenient()).thenReturn(true);
    when(writer.isHtmlSafe()).thenReturn(true);
    when(writer.getSerializeNulls()).thenReturn(true);

    // We simulate AssertionError thrown by Streams.write by subclassing JsonWriter to throw AssertionError on a method called by Streams.write.
    JsonWriter throwingWriter = new JsonWriter(new java.io.StringWriter()) {
      @Override
      public void setLenient(boolean lenient) {
        // do nothing
      }
      @Override
      public void setHtmlSafe(boolean htmlSafe) {
        // do nothing
      }
      @Override
      public void setSerializeNulls(boolean serializeNulls) {
        // do nothing
      }
      @Override
      public boolean isLenient() {
        return true;
      }
      @Override
      public boolean isHtmlSafe() {
        return true;
      }
      @Override
      public boolean getSerializeNulls() {
        return true;
      }
    };

    // Use reflection to replace Streams.write method to throw AssertionError
    // But Streams.write is static final, cannot replace easily.
    // Instead, simulate by calling toJson with a JsonElement that throws AssertionError on toString or similar.
    JsonElement assertionErrorElement = new JsonElement() {
      @Override
      public String toString() {
        throw new AssertionError("test assertion");
      }
    };

    // Act & Assert
    AssertionError error = assertThrows(AssertionError.class, () -> {
      gson.toJson(assertionErrorElement, throwingWriter);
    });
    assertTrue(error.getMessage().contains("GSON"));
    assertTrue(error.getMessage().contains("test assertion"));
  }
}
